/**
 * Economic Monitor - Nexus Economic Intelligence System
 * 
 * Fetches, stores, and analyzes economic indicators
 * Persists across sessions for longitudinal analysis
 */

import { EconomicStore } from './store';
import { fetchCryptoRates } from './indicators/crypto';
import { fetchMarketIndices } from './indicators/indices';
import type { 
  EconomicSnapshot, 
  CryptoRates, 
  MarketIndices,
  MonitorConfig 
} from './types';

export class EconomicMonitor {
  private store: EconomicStore;
  private sessionId: string;
  private config: MonitorConfig;

  constructor(sessionId: string, config?: Partial<MonitorConfig>) {
    this.sessionId = sessionId;
    this.config = {
      dataDir: config?.dataDir || '/home/bootstrap-v17/bootstrap/data/economic',
      maxSnapshots: config?.maxSnapshots || 100,
      sources: {
        crypto: true,
        indices: true,
        rates: false, // Not implemented yet
        labor: false, // Not implemented yet
        ...config?.sources,
      },
    };
    this.store = new EconomicStore(this.config);
  }

  /**
   * Capture a complete economic snapshot
   */
  async capture(): Promise<EconomicSnapshot> {
    const capturedAt = new Date().toISOString();
    const snapshotId = `snap_${Date.now()}_${this.sessionId.slice(-8)}`;

    console.log(`[EconMonitor] Capturing snapshot ${snapshotId}...`);

    // Fetch data from configured sources
    const promises: Promise<unknown>[] = [];

    if (this.config.sources.crypto) {
      promises.push(fetchCryptoRates(this.sessionId));
    }
    if (this.config.sources.indices) {
      promises.push(fetchMarketIndices(this.sessionId));
    }

    const results = await Promise.allSettled(promises);

    // Build snapshot from results
    let crypto: CryptoRates | undefined;
    let indices: MarketIndices | undefined;

    let resultIdx = 0;
    if (this.config.sources.crypto && results[resultIdx]?.status === 'fulfilled') {
      crypto = results[resultIdx].value as CryptoRates;
      resultIdx++;
    }
    if (this.config.sources.indices && results[resultIdx]?.status === 'fulfilled') {
      indices = results[resultIdx].value as MarketIndices;
    }

    // Generate summary
    const summary = this.generateSummary({ crypto, indices });

    const snapshot: EconomicSnapshot = {
      id: snapshotId,
      capturedAt,
      sessionId: this.sessionId,
      crypto,
      indices,
      summary,
    };

    // Persist
    this.store.saveSnapshot(snapshot);
    console.log(`[EconMonitor] Snapshot saved: ${snapshotId}`);

    return snapshot;
  }

  /**
   * Generate a human-readable summary of current conditions
   */
  private generateSummary(data: { 
    crypto?: CryptoRates; 
    indices?: MarketIndices;
  }): string {
    const parts: string[] = [];

    if (data.crypto) {
      const btcPrice = data.crypto.bitcoin.usd.toLocaleString('en-US', {
        style: 'currency',
        currency: 'USD',
      });
      const ethPrice = data.crypto.ethereum.usd.toLocaleString('en-US', {
        style: 'currency',
        currency: 'USD',
      });
      parts.push(`Bitcoin: ${btcPrice}, Ethereum: ${ethPrice}`);
    }

    if (data.indices?.sp500.value) {
      parts.push(`S&P 500: ${data.indices.sp500.value.toLocaleString()}`);
    }

    if (data.indices?.vix.value) {
      const vixLevel = data.indices.vix.value < 15 ? 'low (complacent)' : 
                       data.indices.vix.value > 25 ? 'high (stressed)' : 'moderate';
      parts.push(`VIX: ${data.indices.vix.value.toFixed(2)} (${vixLevel})`);
    }

    return parts.join(' | ') || 'No data captured';
  }

  /**
   * Get the latest snapshot
   */
  getLatestSnapshot(): EconomicSnapshot | null {
    return this.store.loadLatestSnapshot();
  }

  /**
   * Get all historical snapshots
   */
  getHistory(): EconomicSnapshot[] {
    return this.store.loadAllSnapshots();
  }

  /**
   * Get statistics about stored data
   */
  getStats(): ReturnType<EconomicStore['getSnapshotTrends']> {
    return this.store.getSnapshotTrends();
  }

  /**
   * Compare current conditions to previous snapshot
   */
  getChangeSummary(): string {
    const history = this.getHistory();
    if (history.length < 2) {
      return 'Insufficient history for comparison';
    }

    const current = history[history.length - 1];
    const previous = history[history.length - 2];

    const comparisons: string[] = [];

    // Compare crypto
    if (current.crypto?.bitcoin.usd && previous.crypto?.bitcoin.usd) {
      const change = ((current.crypto.bitcoin.usd - previous.crypto.bitcoin.usd) 
                     / previous.crypto.bitcoin.usd * 100).toFixed(2);
      comparisons.push(`BTC: ${change}%`);
    }

    if (current.crypto?.ethereum.usd && previous.crypto?.ethereum.usd) {
      const change = ((current.crypto.ethereum.usd - previous.crypto.ethereum.usd) 
                     / previous.crypto.ethereum.usd * 100).toFixed(2);
      comparisons.push(`ETH: ${change}%`);
    }

    // Compare indices
    if (current.indices?.sp500.value && previous.indices?.sp500.value) {
      const change = ((current.indices.sp500.value - previous.indices.sp500.value)
                     / previous.indices.sp500.value * 100).toFixed(2);
      comparisons.push(`S&P 500: ${change}%`);
    }

    return comparisons.join(', ') || 'No comparable metrics';
  }

  /**
   * Clear all historical data
   */
  clearHistory(): void {
    this.store.clearAll();
    console.log('[EconMonitor] All historical data cleared');
  }
}

/**
 * Economic Monitoring Types
 * Nexus System - Persistent economic observation
 */

export interface Timestamped {
  fetchedAt: string; // ISO 8601
  sessionId: string;
}

export interface CryptoRates extends Timestamped {
  currency: string;
  rates: Record<string, number>; // Symbol -> USD rate
  bitcoin: {
    usd: number;
    change24h: number | null;
  };
  ethereum: {
    usd: number;
    change24h: number | null;
  };
}

export interface MarketIndices extends Timestamped {
  sp500: {
    value: number | null;
    change: number | null;
    error?: string;
  };
  nasdaq: {
    value: number | null;
    change: number | null;
    error?: string;
  };
  vix: { // Volatility index
    value: number | null;
    error?: string;
  };
}

export interface InterestRates extends Timestamped {
  us10y: number | null; // 10-year Treasury
  us2y: number | null;  // 2-year Treasury
  spread10y2y: number | null; // Yield curve indicator
}

export interface LaborSignals extends Timestamped {
  techLayoffs: {
    ytd2025: number; // Running count if available
    trend: 'rising' | 'falling' | 'stable' | 'unknown';
  };
  aiJobPostings: {
    trend: 'rising' | 'falling' | 'stable' | 'unknown';
    notes: string[];
  };
}

export interface EconomicSnapshot {
  id: string;
  capturedAt: string;
  sessionId: string;
  crypto?: CryptoRates;
  indices?: MarketIndices;
  rates?: InterestRates;
  labor?: LaborSignals;
  summary: string; // AI-generated analysis
}

export interface MonitorConfig {
  dataDir: string;
  maxSnapshots: number; // How many to keep
  sources: {
    crypto: boolean;
    indices: boolean;
    rates: boolean;
    labor: boolean;
  };
}

import type { MarketIndices } from '../types';

// Yahoo Finance API (unofficial, may have rate limits)
const YAHOO_API = 'https://query1.finance.yahoo.com/v8/finance/chart';

async function fetchIndex(symbol: string): Promise<{ value: number | null; error?: string }> {
  try {
    const url = `${YAHOO_API}/${symbol}?interval=1d&range=1d`;
    const response = await fetch(url, {
      headers: {
        'User-Agent': 'Mozilla/5.0 (compatible; NexusEcon/1.0)',
      },
    });

    if (!response.ok) {
      return { value: null, error: `HTTP ${response.status}` };
    }

    const data = await response.json();
    const result = data.chart?.result?.[0];

    if (!result || !result.meta) {
      return { value: null, error: 'No data' };
    }

    // Get last regular market price
    const regularMarketPrice = result.meta.regularMarketPrice || null;

    return { value: regularMarketPrice };
  } catch (error) {
    return { 
      value: null, 
      error: error instanceof Error ? error.message : 'Unknown error' 
    };
  }
}

export async function fetchMarketIndices(sessionId: string): Promise<MarketIndices> {
  const fetchedAt = new Date().toISOString();

  // Fetch in parallel
  const [sp500, nasdaq, vix] = await Promise.all([
    fetchIndex('^GSPC'),   // S&P 500
    fetchIndex('^IXIC'),   // NASDAQ Composite
    fetchIndex('^VIX'),    // VIX (Volatility Index)
  ]);

  return {
    fetchedAt,
    sessionId,
    sp500: {
      value: sp500.value,
      change: null, // Would need historical data for change
      error: sp500.error,
    },
    nasdaq: {
      value: nasdaq.value,
      change: null,
      error: nasdaq.error,
    },
    vix: {
      value: vix.value,
      error: vix.error,
    },
  };
}

import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'fs';
import { dirname, join } from 'path';
import type { EconomicSnapshot, MonitorConfig } from './types';

const DEFAULT_CONFIG: MonitorConfig = {
  dataDir: '/home/bootstrap-v17/bootstrap/data/economic',
  maxSnapshots: 100,
  sources: {
    crypto: true,
    indices: true,
    rates: true,
    labor: true,
  },
};

export class EconomicStore {
  private config: MonitorConfig;
  private snapshotsPath: string;
  private indexPath: string;

  constructor(config: Partial<MonitorConfig> = {}) {
    this.config = { ...DEFAULT_CONFIG, ...config };
    this.snapshotsPath = join(this.config.dataDir, 'snapshots.json');
    this.indexPath = join(this.config.dataDir, 'index.json');
    this.ensureStorage();
  }

  private ensureStorage(): void {
    if (!existsSync(this.config.dataDir)) {
      mkdirSync(this.config.dataDir, { recursive: true });
    }
    if (!existsSync(this.indexPath)) {
      this.saveIndex({ snapshots: [], lastSnapshotId: null });
    }
  }

  private loadIndex(): { snapshots: string[]; lastSnapshotId: string | null } {
    if (!existsSync(this.indexPath)) return { snapshots: [], lastSnapshotId: null };
    return JSON.parse(readFileSync(this.indexPath, 'utf-8'));
  }

  private saveIndex(index: { snapshots: string[]; lastSnapshotId: string | null }): void {
    writeFileSync(this.indexPath, JSON.stringify(index, null, 2));
  }

  saveSnapshot(snapshot: EconomicSnapshot): void {
    const index = this.loadIndex();

    // Add to snapshots list
    index.snapshots.push(snapshot.id);
    index.lastSnapshotId = snapshot.id;

    // Trim if exceeding max
    while (index.snapshots.length > this.config.maxSnapshots) {
      const removed = index.snapshots.shift();
      // In full implementation, would delete old snapshot files
    }

    // Save individual snapshot
    const snapshotPath = join(this.config.dataDir, `snapshot_${snapshot.id}.json`);
    writeFileSync(snapshotPath, JSON.stringify(snapshot, null, 2));

    // Save index
    this.saveIndex(index);

    // Append to monolithic file (for easy reading)
    this.appendToSnapshotsFile(snapshot);
  }

  private appendToSnapshotsFile(snapshot: EconomicSnapshot): void {
    let snapshots: EconomicSnapshot[] = [];
    if (existsSync(this.snapshotsPath)) {
      const content = readFileSync(this.snapshotsPath, 'utf-8');
      snapshots = content ? JSON.parse(content) : [];
    }
    snapshots.push(snapshot);

    // Keep only last maxSnapshots
    if (snapshots.length > this.config.maxSnapshots) {
      snapshots = snapshots.slice(-this.config.maxSnapshots);
    }

    writeFileSync(this.snapshotsPath, JSON.stringify(snapshots, null, 2));
  }

  loadAllSnapshots(): EconomicSnapshot[] {
    if (!existsSync(this.snapshotsPath)) return [];
    const content = readFileSync(this.snapshotsPath, 'utf-8');
    return content ? JSON.parse(content) : [];
  }

  loadLatestSnapshot(): EconomicSnapshot | null {
    const snapshots = this.loadAllSnapshots();
    return snapshots.length > 0 ? snapshots[snapshots.length - 1] : null;
  }

  getSnapshotTrends(): { 
    totalSnapshots: number; 
    timeSpan: { first: string | null; last: string | null };
    snapshotIds: string[];
  } {
    const snapshots = this.loadAllSnapshots();
    return {
      totalSnapshots: snapshots.length,
      timeSpan: {
        first: snapshots.length > 0 ? snapshots[0].capturedAt : null,
        last: snapshots.length > 0 ? snapshots[snapshots.length - 1].capturedAt : null,
      },
      snapshotIds: snapshots.map(s => s.id),
    };
  }

  clearAll(): void {
    const index = this.loadIndex();
    for (const id of index.snapshots) {
      const path = join(this.config.dataDir, `snapshot_${id}.json`);
      try {
        if (existsSync(path)) {
          writeFileSync(path, ''); // Clear content but keep file (safer)
        }
      } catch {}
    }
    this.saveIndex({ snapshots: [], lastSnapshotId: null });
    if (existsSync(this.snapshotsPath)) {
      writeFileSync(this.snapshotsPath, '[]');
    }
  }
}

